from pydantic import BaseModel
from lemma_sdk import FunctionContext, Pod
import httpx
import base64

class GenerateAudioInput(BaseModel):
    text: str

class GenerateAudioOutput(BaseModel):
    audio_base64: str
    error: str = ""

async def generate_audio_brief(ctx: FunctionContext, data: GenerateAudioInput) -> GenerateAudioOutput:
    # We use the free HuggingFace Inference API for hexgrad/Kokoro-82M.
    # In a fully production environment, we would inject HF_TOKEN via secrets.
    api_url = "https://api-inference.huggingface.co/models/hexgrad/Kokoro-82M"

    pod = Pod.from_env()
    headers = {"Content-Type": "application/json"}

    try:
        key_bytes = pod.files.download(path="/secrets/hf_token.txt")
        hf_token = key_bytes.decode("utf-8").strip() if isinstance(key_bytes, bytes) else str(key_bytes).strip()
        if hf_token:
            headers["Authorization"] = f"Bearer {hf_token}"
    except Exception:
        pass # Fallback to unauthenticated (might be rate-limited)

    try:
        async with httpx.AsyncClient(timeout=30.0) as client:
            resp = await client.post(
                api_url,
                headers=headers,
                json={"inputs": data.text}
            )
            resp.raise_for_status()
            audio_bytes = resp.content

        b64_audio = base64.b64encode(audio_bytes).decode("utf-8")
        return GenerateAudioOutput(audio_base64=b64_audio)
    except Exception as e:
        return GenerateAudioOutput(audio_base64="", error=f"TTS generation failed: {str(e)}")
